import { invokeBedrockModel } from './bedrock-client';
import { buildCoursePrompt } from './prompts';
import { Course } from '@/types/course';

interface BedrockCourseResponse {
  title: string;
  titleHindi: string;
  description: string;
  duration: string;
  level: string;
  totalHours: number;
  prerequisites: string[];
  modules: Array<{
    week: number;
    title: string;
    titleHindi: string;
    topics: string[];
    estimatedHours: number;
    searchQueries: string[];
  }>;
}

function stripCodeBlock(text: string): string {
  let s = text.trim();
  const tick = String.fromCharCode(96);
  const fence = tick + tick + tick;
  if (s.startsWith(fence)) {
    const firstNewline = s.indexOf(String.fromCharCode(10));
    if (firstNewline !== -1) s = s.substring(firstNewline + 1);
  }
  if (s.endsWith(fence)) {
    s = s.substring(0, s.length - 3);
  }
  return s.trim();
}

export async function generateCourse(
  query: string,
  language: string,
  level: string
): Promise<{ course: Omit<Course, "modules">; searchQueries: string[][] }> {
  const prompt = buildCoursePrompt(query, language, level);
  const responseText = await invokeBedrockModel(prompt);
  const jsonStr = stripCodeBlock(responseText);
  const parsed: BedrockCourseResponse = JSON.parse(jsonStr);
  const courseId = crypto.randomUUID();
  const course = {
    courseId,
    title: parsed.title,
    titleHindi: parsed.titleHindi,
    description: parsed.description,
    duration: parsed.duration,
    level: parsed.level as Course["level"],
    prerequisites: parsed.prerequisites,
    totalHours: parsed.totalHours,
    language,
    createdAt: new Date().toISOString(),
  };
  const searchQueries = parsed.modules.map((m) => m.searchQueries);
  return { course, searchQueries };
}
