import { google } from 'googleapis';

const youtube = google.youtube({ version: 'v3', auth: process.env.YOUTUBE_API_KEY });

export interface YouTubeVideo {
  id: string;
  title: string;
  channel: string;
  thumbnail: string;
  duration: string;
  views: number;
  url: string;
  language: string;
}

export async function searchYouTubeVideos(query: string, language: string = 'hi', maxResults: number = 5): Promise<YouTubeVideo[]> {
  try {
    const searchResponse = await youtube.search.list({
      part: ['snippet'],
      q: query,
      type: ['video'],
      relevanceLanguage: language,
      maxResults,
      videoDuration: 'medium',
      order: 'relevance',
    });
    const videoIds = searchResponse.data.items?.map((item) => item.id?.videoId).filter(Boolean) as string[];
    if (!videoIds.length) return [];
    const detailsResponse = await youtube.videos.list({
      part: ['contentDetails', 'statistics', 'snippet'],
      id: videoIds,
    });
    return (detailsResponse.data.items || []).map((video) => ({
      id: video.id || '',
      title: video.snippet?.title || '',
      channel: video.snippet?.channelTitle || '',
      thumbnail: video.snippet?.thumbnails?.medium?.url || '',
      duration: parseDuration(video.contentDetails?.duration || ''),
      views: parseInt(video.statistics?.viewCount || '0'),
      url: 'https://www.youtube.com/watch?v=' + video.id,
      language,
    }));
  } catch (error) {
    console.error('YouTube API error:', error);
    return [];
  }
}

function parseDuration(iso8601: string): string {
  const match = iso8601.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!match) return '0:00';
  const h = parseInt(match[1] || '0');
  const m = parseInt(match[2] || '0');
  const s = parseInt(match[3] || '0');
  if (h > 0) return h + ':' + String(m).padStart(2, '0') + ':' + String(s).padStart(2, '0');
  return m + ':' + String(s).padStart(2, '0');
}
