export function buildCoursePrompt(query: string, language: string, level: string): string {
  return `You are an expert education curriculum designer for Indian learners.

Create a structured course plan for: "${query}"

Student Level: ${level}
Preferred Language: ${language === 'hi' ? 'Hindi' : 'English'}

IMPORTANT: Return ONLY valid JSON, no markdown, no explanation.

Return this exact JSON structure:
{
  "title": "Course title in English",
  "titleHindi": "Course title in Hindi/Devanagari",
  "description": "2-3 sentence course description",
  "duration": "X weeks",
  "level": "${level}",
  "totalHours": <number>,
  "prerequisites": ["prerequisite 1"],
  "modules": [
    {
      "week": 1,
      "title": "Module title in English",
      "titleHindi": "Module title in Hindi",
      "topics": ["Topic 1", "Topic 2"],
      "estimatedHours": <number>,
      "searchQueries": ["YouTube search query 1", "YouTube search query 2"]
    }
  ]
}

Guidelines:
- Create 6-12 weekly modules depending on topic complexity
- Each module should have 3-5 topics
- Include searchQueries that would find the best FREE YouTube/NPTEL tutorials
- For Hindi language, prefer search queries that find Hindi tutorials (e.g., "Python tutorial Hindi")
- Focus on practical, hands-on learning
- Include projects/assignments in later modules
- Make it suitable for self-paced learning`;
}
