import { NextRequest, NextResponse } from 'next/server';
import { generateCourse } from '@/lib/ai/course-generator';
import { findResources } from '@/lib/content/aggregator';
import { Course, Module } from '@/types/course';

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { query, language = 'hi', level = 'beginner' } = body;
    if (!query || typeof query !== 'string') {
      return NextResponse.json({ error: 'Query is required' }, { status: 400 });
    }
    const { course, searchQueries } = await generateCourse(query, language, level);
    const modules: Module[] = [];
    for (let i = 0; i < searchQueries.length; i++) {
      const resources = await findResources(searchQueries[i], language, 3);
      modules.push({ week: i + 1, title: 'Module ' + (i + 1), titleHindi: '', topics: [], resources, estimatedHours: 5 });
    }
    const fullCourse: Course = { ...course, modules };
    return NextResponse.json(fullCourse);
  } catch (error) {
    console.error('Course generation error:', error);
    return NextResponse.json({ error: 'Failed to generate course. Please try again.' }, { status: 500 });
  }
}
