import { searchYouTubeVideos, YouTubeVideo } from './youtube-client';
import { Resource } from '@/types/course';

export async function findResources(
  searchQueries: string[],
  language: string = 'hi',
  maxPerQuery: number = 3
): Promise<Resource[]> {
  const allResources: Resource[] = [];

  for (const query of searchQueries) {
    const videos = await searchYouTubeVideos(query, language, maxPerQuery);
    const resources = videos.map(videoToResource);
    allResources.push(...resources);
  }

  // Deduplicate by video ID
  const seen = new Set<string>();
  return allResources.filter((r) => {
    if (seen.has(r.id)) return false;
    seen.add(r.id);
    return true;
  });
}

function videoToResource(video: YouTubeVideo): Resource {
  return {
    id: video.id,
    type: 'youtube',
    title: video.title,
    url: video.url,
    duration: video.duration,
    language: video.language,
    channel: video.channel,
    thumbnail: video.thumbnail,
    views: video.views,
  };
}
